WITH CC AS (
		SELECT
		NivelAcao.CODCCUSTO COLLATE SQL_Latin1_General_CP1_CI_AI AS CODCCUSTO,
		NivelUnidade.CAMPOLIVRE AS ACAO,
		CASE WHEN NivelProjeto.CAMPOLIVRE LIKE 'Sebrae Aqui - Inaugurações e Revitalizações' THEN 'Sebrae Aqui - Inauguração e Revitalização' ELSE NivelProjeto.CAMPOLIVRE END AS PROJETO,
		NivelAcao.CAMPOLIVRE AS UNIDADE,
		UPPER(CONCAT(NivelProjeto.CAMPOLIVRE,NivelUnidade.CAMPOLIVRE,NivelAcao.CAMPOLIVRE)) AS CHAVE_CONCAT
		FROM HUBDADOS.CorporeRM.GCCUSTO AS NivelAcao
		-- Corrigindo a lógica para buscar os níveis hierárquicos corretos
		LEFT JOIN HUBDADOS.CorporeRM.GCCUSTO AS NivelProjeto ON LEFT(NivelAcao.CODCCUSTO, 5) = NivelProjeto.CODCCUSTO
		LEFT JOIN HUBDADOS.CorporeRM.GCCUSTO AS NivelUnidade ON LEFT(NivelAcao.CODCCUSTO, 12) = NivelUnidade.CODCCUSTO
		WHERE 
		LEN(NivelAcao.CODCCUSTO) = 16
	)

, NACIONAL AS (SELECT a.* FROM financa.dbo.[dex-orcado] A WHERE nm_ppa IN ('PPA 2025 - 2025/Mar','PPA 2026 - 2026/Mar'))


,MAPA AS (
SELECT A.*,B.PROJETO,B.ACAO,B.UNIDADE FROM #mapa_orcamento25 A LEFT JOIN CC B ON B.CODCCUSTO = A.CC
UNION
SELECT A.*,B.PROJETO,B.ACAO,B.UNIDADE FROM #mapa_orcamento26 A LEFT JOIN CC B ON B.CODCCUSTO = A.CC
)



SELECT A.*,B.CC FROM [DEX-orcado] A
LEFT JOIN MAPA B ON CONCAT(B.ANO,B.PROJETO,B.ACAO,B.UNIDADE) COLLATE SQL_Latin1_General_CP1_CI_AI = CONCAT(A.VL_ANO,A.NM_INICIATIVA,A.NM_ACAO,A.NM_UNIDADE)
WHERE nm_iniciativa NOT LIKE 'CANCELADO%'